// Content with portions generated by generative AI platform
package org.eclipse.kura.web.server.net2.configuration;

import static org.junit.Assert.assertEquals;
import static org.junit.Assert.assertFalse;
import static org.junit.Assert.assertTrue;

import java.util.Map;

import org.eclipse.kura.configuration.Password;
import org.eclipse.kura.web.server.util.GwtServerUtil;
import org.eclipse.kura.web.shared.GwtKuraException;
import org.eclipse.kura.web.shared.model.GwtModemAuthType;
import org.eclipse.kura.web.shared.model.GwtModemInterfaceConfig;
import org.eclipse.kura.web.shared.model.GwtNetIfConfigMode;
import org.eclipse.kura.web.shared.model.GwtNetIfStatus;
import org.eclipse.kura.web.shared.model.GwtNetInterfaceConfig;
import org.eclipse.kura.web.shared.model.GwtNetRouterMode;
import org.eclipse.kura.web.shared.model.GwtWifiNetInterfaceConfig;
import org.junit.Test;

public class PreventModemPasswordPlaceholderTest {

    private static final String INTERFACE_NAME = "testInterface";
    private static final String PASSWORD_KEY = "net.interface.testInterface.config.password";

    private GwtModemInterfaceConfig modemConfig;
    private GwtNetInterfaceConfig oldConfig;
    private Map<String, Object> result;

    @Test
    public void placeholderPasswordWithModemOldConfigUsesOldPassword() {
        givenModemConfigWithPassword(GwtServerUtil.PASSWORD_PLACEHOLDER);
        givenOldModemConfigWithPassword("oldSecretPassword");

        whenBuildingProperties();

        thenModemPasswordIs("oldSecretPassword");
    }

    @Test
    public void placeholderPasswordWithNonModemOldConfigDoesNotStorePassword() {
        givenModemConfigWithPassword(GwtServerUtil.PASSWORD_PLACEHOLDER);
        givenOldWifiConfig();

        whenBuildingProperties();

        thenModemPasswordIsNotStored();
    }

    @Test
    public void realPasswordIsStoredAsIsWithNonModemOldConfig() {
        givenModemConfigWithPassword("myRealPassword");
        givenOldWifiConfig();

        whenBuildingProperties();

        thenModemPasswordIs("myRealPassword");
    }

    @Test
    public void realPasswordIsStoredAsIsWithModemOldConfig() {
        givenModemConfigWithPassword("myRealPassword");
        givenOldModemConfigWithPassword("oldPassword");

        whenBuildingProperties();

        thenModemPasswordIs("myRealPassword");
    }

    private void givenModemConfigWithPassword(String password) {
        modemConfig = new GwtModemInterfaceConfig();
        modemConfig.setName(INTERFACE_NAME);
        modemConfig.setStatus(GwtNetIfStatus.netIPv4StatusEnabledLAN.name());
        modemConfig.setIpv6Status("netIPv6StatusDisabled");
        modemConfig.setConfigMode(GwtNetIfConfigMode.netIPv4ConfigModeDHCP.name());
        modemConfig.setRouterMode(GwtNetRouterMode.netRouterOff.name());
        modemConfig.setAuthType(GwtModemAuthType.netModemAuthNONE);
        modemConfig.setPassword(password);
        modemConfig.setUsername("testUser");
        modemConfig.setDialString("testDial");
    }

    private void givenOldModemConfigWithPassword(String password) {
        GwtModemInterfaceConfig oldModemConfig = new GwtModemInterfaceConfig();
        oldModemConfig.setName(INTERFACE_NAME);
        oldModemConfig.setPassword(password);
        oldConfig = oldModemConfig;
    }

    private void givenOldWifiConfig() {
        GwtWifiNetInterfaceConfig oldWifiConfig = new GwtWifiNetInterfaceConfig();
        oldWifiConfig.setName(INTERFACE_NAME);
        oldConfig = oldWifiConfig;
    }

    private void whenBuildingProperties() throws GwtKuraException {
        NetworkConfigurationServicePropertiesBuilder builder = new NetworkConfigurationServicePropertiesBuilder(
                modemConfig, oldConfig);
        result = builder.build();
    }

    private void thenModemPasswordIs(String expectedPassword) {
        assertTrue("Modem password should be stored", result.containsKey(PASSWORD_KEY));
        Object passwordObj = result.get(PASSWORD_KEY);
        assertTrue("Password should be a Password instance", passwordObj instanceof Password);
        assertEquals(expectedPassword, new String(((Password) passwordObj).getPassword()));
    }

    private void thenModemPasswordIsNotStored() {
        assertFalse("Modem password should not be stored when placeholder detected and old config is not modem",
                result.containsKey(PASSWORD_KEY));
    }
}